    "id": "remote-bind-without-opt-in",
    "severity": "HIGH",
    "category": "security",
    "location": "scripts/ai_agent_bridge/_cli.py:762",
    "description": "The proxy accepts any --host value and passes it directly to uvicorn without an explicit remote-exposure opt-in or authentication. Although the default is 127.0.0.1, a user or wrapper can bind 0.0.0.0 and expose local agent CLIs and their credentials/configuration to the network; this conflicts with the documented localhost-only boundary and can let remote callers run costly or sensitive model requests."
  },
  {
    "id": "unbounded-request-body",
    "severity": "MEDIUM",
    "category": "dos-surface",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:33",
    "description": "Chat messages accept arbitrary-size strings and content lists with no request body, message count, or prompt length limit before flattening and forwarding to subprocesses. A large request can consume memory in FastAPI/Pydantic, produce a huge CLI argument/stdin payload, and amplify resource usage in backend agents."
  },
  {
    "id": "unbounded-subprocess-fanout",
    "severity": "MEDIUM",
    "category": "dos-surface",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:289",
    "description": "Each /v1/chat/completions request synchronously launches a backend CLI, but the service has no concurrency limit, queue, rate limit, or admission control. Multiple clients or retries from OpenAI-compatible SDKs can spawn many long-running agent processes at once, exhausting CPU, memory, API quotas, or local CLI session limits even with the per-process timeout."
  },
  {
    "id": "stream-parameter-ignored",
    "severity": "LOW",
    "category": "spec-compliance",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:289",
    "description": "The request model allows extra OpenAI fields, but chat_completions ignores stream=true and still returns a normal JSON completion. OpenAI-compatible clients that request streaming will expect an SSE response and may hang, fail parsing, or incorrectly treat the proxy as streaming-capable; unsupported streaming should be rejected explicitly until implemented."
  }
]

